function initRakeCalc(){var root=document.getElementById("rake-calc-app");if(!root)return;injectStyles();root.classList.add("op-tools");var gameType="NLH";var stakes="micro";var handsPerDay=500;var rakeDiv=el("div",{className:"op-rake"});root.appendChild(rakeDiv);var STAKES_OPTIONS=[{value:"micro",label:"Micro (NL2-NL10)"},{value:"low",label:"Low (NL25-NL50)"},{value:"mid",label:"Mid (NL100-NL200)"}];function render(){rakeDiv.innerHTML="";var controls=el("div",{className:"op-rake__controls"});var gameGroup=el("div",{className:"op-rake__group"});gameGroup.appendChild(el("label",{textContent:"Game Type"}));var gameRadios=el("div",{className:"op-rake__radios"});["NLH","PLO"].forEach(function(g){var btn=el("button",{className:"op-rake__radio"+(gameType===g?" op-rake__radio--active":""),textContent:g,onClick:function(){gameType=g;render();}});gameRadios.appendChild(btn);});gameGroup.appendChild(gameRadios);controls.appendChild(gameGroup);var stakesGroup=el("div",{className:"op-rake__group"});stakesGroup.appendChild(el("label",{textContent:"Stakes"}));var stakesSelect=el("select",{className:"op-rake__select",onChange:function(){stakes=stakesSelect.value;render();}});STAKES_OPTIONS.forEach(function(o){var opt=el("option",{value:o.value,textContent:o.label});if(o.value===stakes)opt.selected=true;stakesSelect.appendChild(opt);});stakesGroup.appendChild(stakesSelect);controls.appendChild(stakesGroup);var handsGroup=el("div",{className:"op-rake__group"});handsGroup.appendChild(el("label",{textContent:"Hands per Day"}));var sliderVal=el("span",{className:"op-rake__slider-val",textContent:handsPerDay});var slider=el("input",{type:"range",className:"op-rake__slider",min:"100",max:"2000",step:"100",value:String(handsPerDay)});slider.addEventListener("input",function(){handsPerDay=parseInt(slider.value);sliderVal.textContent=handsPerDay;updateCalc();});var sliderWrap=el("div",{className:"op-rake__slider-wrap"},[slider,sliderVal]);handsGroup.appendChild(sliderWrap);controls.appendChild(handsGroup);rakeDiv.appendChild(controls);var tableWrap=el("div",{className:"op-rake__table-wrap"});var table=el("table",{className:"op-rake__table",id:"op-rake-table"});tableWrap.appendChild(table);rakeDiv.appendChild(tableWrap);var chartDiv=el("div",{className:"op-rake__chart",id:"op-rake-chart"});rakeDiv.appendChild(chartDiv);rakeDiv.appendChild(el("div",{className:"op-rake__note",innerHTML:"<strong>Note:</strong> Actual rake depends on pot sizes and player count. These are estimates based on average rake cap per hand for comparison purposes. PLO caps are approximately 20% higher than NLH at equivalent stakes."}));updateCalc();}
function updateCalc(){var caps=RAKE_DATA[gameType][stakes];if(!caps)return;var results=[];BRANDS.forEach(function(b){var cap=caps[b.id];if(cap===undefined)return;var avgRakePerHand=cap*0.6;var dailyRake=avgRakePerHand*handsPerDay;var monthlyRake=dailyRake*30;results.push({brand:b,cap:cap,daily:dailyRake,monthly:monthlyRake});});results.sort(function(a,b){return a.monthly-b.monthly;});var table=document.getElementById("op-rake-table");if(!table)return;table.innerHTML="";var thead=el("thead");var headerRow=el("tr");["Rank","Room","Rake Cap","Est. Daily Rake","Est. Monthly Rake",""].forEach(function(h){headerRow.appendChild(el("th",{textContent:h}));});thead.appendChild(headerRow);table.appendChild(thead);var tbody=el("tbody");var minMonthly=results[0]?results[0].monthly:0;results.forEach(function(r,idx){var row=el("tr");if(r.monthly<=minMonthly)row.classList.add("op-rake-best");row.appendChild(el("td",{textContent:"#"+(idx+1)}));row.appendChild(el("td",{innerHTML:"<strong>"+r.brand.name+"</strong>"}));row.appendChild(el("td",{textContent:"C$"+r.cap.toFixed(2)}));row.appendChild(el("td",{textContent:"C$"+r.daily.toFixed(2)}));row.appendChild(el("td",{innerHTML:"<strong>C$"+r.monthly.toFixed(2)+"</strong>"}));row.appendChild(el("td",{innerHTML:'<a href="'+reviewUrl(r.brand.id)+'" style="font-size:0.75rem;">Full Review →</a>'}));tbody.appendChild(row);});table.appendChild(tbody);var chartDiv=document.getElementById("op-rake-chart");if(!chartDiv)return;chartDiv.innerHTML="";var maxMonthly=results.length?results[results.length-1].monthly:1;results.forEach(function(r){var pct=maxMonthly>0?(r.monthly/maxMonthly)*100:0;var barEl=el("div",{className:"op-rake__chart-bar",style:{width:"0%",background:r.brand.accentColor}},[el("span",{textContent:"C$"+r.monthly.toFixed(0)})]);var row=el("div",{className:"op-rake__chart-row"},[el("div",{className:"op-rake__chart-label",textContent:r.brand.name}),el("div",{className:"op-rake__chart-bar-wrap"},[barEl])]);chartDiv.appendChild(row);setTimeout(function(){barEl.style.width=Math.max(pct,8)+"%";},100);});}
render();}
